<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdisk</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/block/sda</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # sda can be sda, sdb, or other letters</span></span>
